import{u as p,c,a as e,t as l,g as o,d as a,h as g,b as m,o as d,r as x}from"./DSXc2kwK.js";import{u as f}from"./DCPTHGlb.js";import{u}from"./xdB0Cksp.js";const h={class:"mx-auto flex max-w-5xl flex-col gap-6 px-6 py-16 text-gray-700"},b={class:"text-xl md:text-2xl"},_={class:"flex justify-center"},y=["href"],i="Монтаж и профилактика на климатици, ремонти на бани и кухни, дограма и вътрешни довършителни работи във Варна. Над 14 години опит. Обадете се за оглед и оферта.",B={__name:"index",setup(N){const s=p(),r=f().url||"https://remonti-varna.bg",n=`Климатизация и ремонти във Варна | ${s.siteName}`;return u({title:n,link:[{rel:"canonical",href:r}],meta:[{name:"description",content:i},{property:"og:url",content:r},{property:"og:title",content:n},{property:"og:description",content:i},{name:"twitter:title",content:n},{name:"twitter:description",content:i}]}),(v,t)=>(d(),c("main",h,[t[1]||(t[1]=e("h1",{class:"text-3xl md:text-5xl font-semibold leading-tight"}," Климатизация и ремонти във Варна ",-1)),e("h2",b,[e("strong",null,l(o(s).siteName),1),t[0]||(t[0]=a(" - 14 години опит, доверие и професионализъм в сферата на климатизацията и ремонтните дейности във Варна. ",-1))]),t[2]||(t[2]=g('<p> Вашият надежден партньор в областта на климатизацията, вентилацията и строително-ремонтните дейности във Варна и региона. В отговор на динамичния пазар и нуждите на нашите клиенти, с времето разширихме дейността си. Днес предлагаме цялостно управление и изпълнение на проекти - от строително-ремонтни дейности, през вътрешно обзавеждане, до външни мазилки, изолации и довършителни работи за напълно завършена визия. </p><p> Ние поемаме пълната отговорност за всеки етап от проекта, като гарантираме правилното функциониране на изградените системи и инсталации до окончателното завършване на обекта. С нас клиентите получават качество, сигурност и спокойствие - увереност, че са направили правилния избор и че инвестицията им е в надеждни ръце. Работим на територията на град Варна и близките населени места, като поемаме проекти в цялата страна по договорка. </p><div><p class="font-semibold mb-4">Специализирани сме в:</p><ul class="list-disc space-y-2 pl-5"><li><strong>Монтаж и сервиз на климатици във Варна</strong> - доставка, монтаж, профилактика и поддръжка на климатични системи за жилища и търговски обекти. </li><li><strong>Вентилационни системи</strong> - проектиране, изграждане и обслужване на вентилация за домове, офиси и обекти. </li><li><strong>Цялостни и частични ремонти</strong> - довършителни работи, изолации и външни подобрения. </li><li><strong>Електро и ВиК услуги</strong> - изграждане и ремонт на електро и водопроводни инсталации. </li><li><strong>Монтажи и логистика</strong> - монтаж на дограма и оборудване, транспорт на материали и извозване на отпадъци. </li></ul></div><p> За нас доверието се гради на резултати, а успехът през годините се дължи на доволните ни клиенти. Затова подхождаме към всеки проект с внимание към детайла и професионално отношение. </p><p><strong><i>“Има ли желание - има и начин.”</i></strong><br> Това е принципът, който следваме във всеки проект, за да удовлетворим Вашите изисквания. </p>',5)),e("div",_,[e("a",{class:"inline-flex items-center gap-2 rounded-full bg-black px-5 py-3 text-sm font-semibold text-white transition hover:bg-teal-700 hover:text-white",href:`tel:${o(s).phoneNumberRaw}`},[m(o(x),{class:"h-4 w-4"}),a(" Обадете ни се: "+l(o(s).phoneNumber),1)],8,y)])]))}};export{B as default};
